// paymentModule/ApplePayProvider.js
import { NativeModules } from 'react-native';

const { ApplePayModule } = NativeModules;

export class ApplePayProvider {
  async isAvailable() {
    try {
      return await ApplePayModule.canMakePayments();
    } catch (error) {
      return false;
    }
  }

  async requestPayment(paymentRequest) {
    try {
      const result = await ApplePayModule.presentPaymentRequest({
        merchantIdentifier: paymentRequest.merchantId,
        supportedNetworks: paymentRequest.supportedNetworks || ['visa', 'mastercard', 'amex'],
        merchantCapabilities: ['3DS', 'debit', 'credit'],
        countryCode: paymentRequest.countryCode || 'US',
        currencyCode: paymentRequest.currency,
        paymentSummaryItems: [{
          label: paymentRequest.label,
          amount: paymentRequest.amount.toString()
        }]
      });

      return {
        success: true,
        paymentData: result.paymentData,
        transactionIdentifier: result.transactionIdentifier
      };
    } catch (error) {
      throw new Error(`Apple Pay failed: ${error.message}`);
    }
  }

  async completeTransaction(success) {
    try {
      await ApplePayModule.completeTransaction(success);
    } catch (error) {
      console.error('Failed to complete transaction:', error);
    }
  }
}


