import { NativeModules } from 'react-native';

const { GooglePayModule } = NativeModules;

export class GooglePayProvider {
  async isAvailable() {
    try {
      return await GooglePayModule.isReadyToPay({
        apiVersion: 2,
        apiVersionMinor: 0,
        allowedPaymentMethods: [{
          type: 'CARD',
          parameters: {
            allowedAuthMethods: ['PAN_ONLY', 'CRYPTOGRAM_3DS'],
            allowedCardNetworks: ['MASTERCARD', 'VISA', 'AMEX']
          }
        }]
      });
    } catch (error) {
      return false;
    }
  }

  async requestPayment(paymentRequest) {
    try {
      const paymentDataRequest = {
        apiVersion: 2,
        apiVersionMinor: 0,
        merchantInfo: {
          merchantId: paymentRequest.merchantId,
          merchantName: paymentRequest.merchantName
        },
        allowedPaymentMethods: [{
          type: 'CARD',
          parameters: {
            allowedAuthMethods: ['PAN_ONLY', 'CRYPTOGRAM_3DS'],
            allowedCardNetworks: paymentRequest.supportedNetworks || ['MASTERCARD', 'VISA', 'AMEX']
          },
          tokenizationSpecification: {
            type: 'PAYMENT_GATEWAY',
            parameters: {
              gateway: paymentRequest.gateway || 'stripe',
              gatewayMerchantId: paymentRequest.gatewayMerchantId
            }
          }
        }],
        transactionInfo: {
          totalPriceStatus: 'FINAL',
          totalPrice: paymentRequest.amount.toString(),
          currencyCode: paymentRequest.currency,
          countryCode: paymentRequest.countryCode || 'US'
        }
      };

      const result = await GooglePayModule.loadPaymentData(paymentDataRequest);

      return {
        success: true,
        paymentData: result.paymentMethodData,
        token: result.paymentMethodData.tokenizationData.token
      };
    } catch (error) {
      throw new Error(`Google Pay failed: ${error.message}`);
    }
  }
}


// paymentModule/StripeProvider.js
export class StripeProvider {
  constructor(publishableKey) {
    this.publishableKey = publishableKey;
    this.apiUrl = 'https://api.stripe.com/v1';
  }

  async createPaymentIntent(amount, currency, metadata = {}) {
    try {
      const response = await fetch(`${this.apiUrl}/payment_intents`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.publishableKey}`,
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: this.encodeFormData({
          amount: Math.round(amount * 100),
          currency: currency.toLowerCase(),
          metadata
        })
      });

      const data = await response.json();
      
      if (data.error) {
        throw new Error(data.error.message);
      }

      return {
        clientSecret: data.client_secret,
        paymentIntentId: data.id
      };
    } catch (error) {
      throw new Error(`Stripe payment intent failed: ${error.message}`);
    }
  }

  async confirmPayment(clientSecret, paymentMethodId) {
    try {
      const response = await fetch(`${this.apiUrl}/payment_intents/${clientSecret.split('_secret_')[0]}/confirm`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.publishableKey}`,
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: this.encodeFormData({
          payment_method: paymentMethodId,
          client_secret: clientSecret
        })
      });

      const data = await response.json();
      
      if (data.error) {
        throw new Error(data.error.message);
      }

      return {
        success: data.status === 'succeeded',
        status: data.status,
        paymentIntentId: data.id
      };
    } catch (error) {
      throw new Error(`Stripe payment confirmation failed: ${error.message}`);
    }
  }

  encodeFormData(data) {
    return Object.keys(data)
      .map(key => {
        if (typeof data[key] === 'object') {
          return Object.keys(data[key])
            .map(subKey => `${encodeURIComponent(key)}[${encodeURIComponent(subKey)}]=${encodeURIComponent(data[key][subKey])}`)
            .join('&');
        }
        return `${encodeURIComponent(key)}=${encodeURIComponent(data[key])}`;
      })
      .join('&');
  }
}


// paymentModule/PaymentProviderFactory.js
import { ApplePayProvider } from './ApplePayProvider';
import { GooglePayProvider } from './GooglePayProvider';
import { StripeProvider } from './StripeProvider';
import { Platform } from 'react-native';

export class PaymentProviderFactory {
  static createProvider(type, config = {}) {
    switch (type) {
      case 'apple_pay':
        if (Platform.OS !== 'ios') {
          throw new Error('Apple Pay only available on iOS');
        }
        return new ApplePayProvider();
      
      case 'google_pay':
        if (Platform.OS !== 'android') {
          throw new Error('Google Pay only available on Android');
        }
        return new GooglePayProvider();
      
      case 'stripe':
        if (!config.publishableKey) {
          throw new Error('Stripe publishable key required');
        }
        return new StripeProvider(config.publishableKey);
      
      default:
        throw new Error(`Unknown payment provider: ${type}`);
    }
  }

  static async getAvailableProviders() {
    const providers = [];

    if (Platform.OS === 'ios') {
      const applePay = new ApplePayProvider();
      if (await applePay.isAvailable()) {
        providers.push('apple_pay');
      }
    }

    if (Platform.OS === 'android') {
      const googlePay = new GooglePayProvider();
      if (await googlePay.isAvailable()) {
        providers.push('google_pay');
      }
    }

    providers.push('stripe');
    providers.push('credit_card');

    return providers;
  }
}